class AfroRelatedTools extends HTMLElement{constructor(){super();this.attachShadow({mode:"open"})}static get observedAttributes(){return["category","current"]}connectedCallback(){this._render()}attributeChangedCallback(){if(this.shadowRoot)this._render()}_getTools(){const e=this.getAttribute("category")||"",t=this.getAttribute("current")||"",s=(typeof AFRO_TOOLS!=="undefined"?AFRO_TOOLS:[]).filter(o=>o.status==="live"&&o.id!==t),r=s.filter(o=>o.category===e).sort((o,a)=>(a.priority||0)-(o.priority||0)),n=s.filter(o=>o.category!==e).sort((o,a)=>(a.estTraffic||0)-(o.estTraffic||0));let i=r.slice(0,6);if(i.length<4){const o=new Set(i.map(a=>a.id));i=i.concat(n.filter(a=>!o.has(a.id)).slice(0,4-i.length))}return i.slice(0,6)}_render(){const e=this._getTools();if(e.length===0){this.shadowRoot.innerHTML="";return}const t=e.map(s=>`<a href="${s.href}" class="rt-card"><span class="rt-icon">${s.icon}</span><div class="rt-info"><span class="rt-name">${s.name}</span><span class="rt-desc">${s.desc}</span></div></a>`).join("");this.shadowRoot.innerHTML=`<style>:host{display:block;font-family:'DM Sans',system-ui,-apple-system,sans-serif;max-width:1200px;margin:0 auto;padding:48px 20px 32px}.rt-header{text-align:center;margin-bottom:32px}.rt-title{font-size:1.5rem;font-weight:700;color:#1a1a1a;margin:0 0 8px}.rt-subtitle{font-size:.95rem;color:#666;margin:0}.rt-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-bottom:24px}.rt-card{display:flex;align-items:flex-start;gap:12px;padding:16px;background:#fff;border:1px solid #e5e7eb;border-radius:12px;text-decoration:none;color:inherit;transition:transform .2s ease,border-color .2s ease,box-shadow .2s ease}.rt-card:hover{transform:translateY(-3px);border-color:#0071E3;box-shadow:0 4px 12px rgba(0,113,227,.1)}.rt-icon{font-size:1.75rem;flex-shrink:0;line-height:1;margin-top:2px}.rt-info{display:flex;flex-direction:column;gap:4px;min-width:0}.rt-name{font-size:.95rem;font-weight:600;color:#1a1a1a;line-height:1.3}.rt-desc{font-size:.8rem;color:#666;line-height:1.45;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}.rt-browse{text-align:center}.rt-browse a{display:inline-block;font-size:.95rem;font-weight:600;color:#0071E3;text-decoration:none;padding:10px 24px;border:2px solid #0071E3;border-radius:8px;transition:background .2s ease,color .2s ease}.rt-browse a:hover{background:#0071E3;color:#fff}@media(max-width:900px){.rt-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:560px){:host{padding:32px 16px 24px}.rt-grid{grid-template-columns:1fr}.rt-title{font-size:1.25rem}}</style><div class="rt-header"><h2 class="rt-title">You might also like</h2><p class="rt-subtitle">Discover more free tools on AfroTools</p></div><div class="rt-grid">${t}</div><div class="rt-browse"><a href="/all-tools/">Browse all tools &rarr;</a></div>`}}customElements.define("afro-related-tools",AfroRelatedTools);
